import { existsSync } from "fs";
import { resolve } from "path";
import { pathToFileURL } from "url";

/**
 * Attempts to load envx.config.js (or envx.config.mjs / envx.config.cjs)
 * from the current working directory.
 *
 * Returns null if no config file is found.
 *
 * @returns {Promise<EnvxConfig|null>}
 */
export async function loadConfig() {
  const candidates = [
    "envx.config.js",
    "envx.config.mjs",
    "envx.config.cjs",
  ];

  for (const filename of candidates) {
    const fullPath = resolve(process.cwd(), filename);
    if (existsSync(fullPath)) {
      try {
        const fileUrl = pathToFileURL(fullPath).href;
        const mod = await import(fileUrl);
        const config = mod.default ?? mod;

        // Support both flat schema { KEY: rule } and { strict, schema: { KEY: rule } }
        if (config && typeof config === "object") {
          if (config.schema) {
            // Structured format: { strict?, schema: {...} }
            return {
              strict: config.strict ?? false,
              schema: config.schema,
            };
          } else {
            // Flat format: { KEY: rule, ... }
            const { strict, ...schema } = config;
            return {
              strict: strict ?? false,
              schema,
            };
          }
        }
      } catch (err) {
        throw new Error(`Failed to load ${filename}: ${err.message}`);
      }
    }
  }

  return null;
}
